import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse('{"title":"multi-agent-orchestrator","description":"","frontmatter":{"title":"multi-agent-orchestrator","concept":"多 Agent 编排模式","concept_id":"multi-agent-orchestrator","aliases":["Orchestrator-subagent 模式","Sub-agent 分发"],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] Run multiple agents at once with _fleet in Copilot CLI.md","02_Library/Agent_Architecture/[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md"],"related_concepts":["[[agent-teams-pattern]]","[[message-bus-pattern]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/multi-agent-orchestrator.md","filePath":"wiki/concepts/multi-agent-orchestrator.md","lastUpdated":null}'),i={name:"wiki/concepts/multi-agent-orchestrator.md"};function o(s,t,l,c,h,u){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="多-agent-编排模式-multi-agent-orchestrator" tabindex="-1">多 Agent 编排模式 (Multi-Agent Orchestrator) <a class="header-anchor" href="#多-agent-编排模式-multi-agent-orchestrator" aria-label="Permalink to &quot;多 Agent 编排模式 (Multi-Agent Orchestrator)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>中心化的任务拆解架构。主（Orchestrator）Agent 负责将复杂请求解耦为子模块并识别依赖性，继而并发地分发给多个临时生命周期的子（Sub-Agent）完成各自单一指令，最终由主脑合并产物。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>中心单点依赖</strong>：所有信息路由和聚合依赖于控制中心（Lead Agent）。非常易于控制输出质量且过程可控（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_...</a>）</li><li><strong>独立环境无文件锁</strong>：多个并发的 Agent 不存在底层文件操作锁，分配任务时若操作相同文件会导致被覆盖（来源：<a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.html">[AI_IDE_And_CLI] Run multiple agents at once...</a>）</li><li><strong>临时且聚焦的上下文</strong>：Sub-Agent 不需要保留多次迭代的大长文历史，它们只需快速解决当前独立子分支，然后消亡。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p><strong>适用场景</strong>：任务步骤确定、输出件边界极其清晰的任务（如代码 Review 各阶段分发、特定文档区块补全）。 <strong>避坑指南</strong>：向 Sub Agent 下发工作项时，需要在 Prompt 内严格界定边界和互斥目标路径以防止互相交叉覆盖文件。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/artifact-driven-decomposition.html">artifact-driven-decomposition</a> — 为 Orchestrator 提供精确拆解指令的具体技术。</li><li><a href="/s/webclips/wiki/concepts/agent-teams-pattern.html">agent-teams-pattern</a> — 当需要 Agent 在跨周期内保存长时知识或连续多步骤交互时，应放弃编排模式转为团队模式。</li></ul><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_...</a></td><td>&quot;A lead agent receives a task and determines how to approach it... Subagents complete their work and return results, which the orchestrator synthesizes into a final output.&quot;</td></tr></tbody></table>',11)])])}const p=e(i,[["render",o]]);export{g as __pageData,p as default};
